tests.expect_optimized_program:
define i32 @log2_ceil_i32(i32 %x) {
  %sub = add i32 %x, -1
  %ctlz = call i32 @llvm.ctlz.i32(i32 %sub, i1 false)
  %ret = sub nuw nsw i32 32, %ctlz
  ret i32 %ret
}

define i32 @ceil_div_i32(i32 %x, i32 %y) {
  %bminus1 = add i32 %y, -1
  %add = add i32 %x, %bminus1
  %div = udiv i32 %add, %y
  ret i32 %div
}

define i64 @log2_ceil_i64_with_trunc(i64 %x) {
  %sub = add i64 %x, -1
  %ctlz = call i64 @llvm.ctlz.i64(i64 %sub, i1 false)
  %ret = sub nuw nsw i64 64, %ctlz
  ret i64 %ret
}
